const crypto = require('crypto');

const safeStringify = (value, max = 12000) => {
  try {
    const text = typeof value === 'string' ? value : JSON.stringify(value ?? {}, null, 2);
    return text.length > max ? text.slice(0, max) + `... [truncated ${text.length - max} chars]` : text;
  } catch (e) {
    return String(value ?? '').slice(0, max);
  }
};

const redact = (obj) => {
  const deny = /password|passwd|pwd|secret|token|api[_-]?key|authorization|cookie|set-cookie|client_secret|refresh_token|access_token/i;
  const walk = (v) => {
    if (Array.isArray(v)) return v.map(walk);
    if (v && typeof v === 'object') {
      return Object.fromEntries(Object.entries(v).map(([k, val]) => [k, deny.test(k) ? '[REDACTED]' : walk(val)]));
    }
    return v;
  };
  return walk(obj);
};

const now = new Date().toISOString();
return $input.all().map((item) => {
  const j = item.json || {};
  const error = j.error || j.execution?.error || j.trigger?.error || {};
  const workflow = j.workflow || j.execution?.workflowData || {};
  const execution = j.execution || {};
  const source = redact(j);
  const correlationId = j.correlationId || execution.id || crypto.randomUUID();
  const message = error.message || error.description || j.message || j.errorMessage || 'Unknown n8n workflow error';
  const stack = error.stack || error.stacktrace || null;
  const failedNode = error.node?.name || error.nodeName || execution.lastNodeExecuted || null;

  const businessData = {
    correlationId,
    severity: j.severity || 'ERROR',
    failedNode,
    executionId: execution.id || j.executionId || null,
    executionUrl: execution.url || j.executionUrl || null,
    mode: execution.mode || j.mode || null,
    retryRecommended: Boolean(j.retryRecommended ?? true),
    retryCount: Number(j.retryCount || 0),
    stack,
    inputSummary: source.businessData || source.payload || source.body || null,
    rawErrorEvent: source,
  };

  return {
    json: {
      ErrorLogID: `ERR-${Date.now()}-${crypto.randomUUID().slice(0, 8)}`,
      ErrorLogDate: now,
      ErrorMessage: String(message).slice(0, 2000),
      WorkflowID: String(workflow.id || j.workflowId || $workflow.id || 'unknown'),
      WorkflowName: String(workflow.name || j.workflowName || $workflow.name || 'unknown'),
      BusinessData: safeStringify(businessData),
    }
  };
});

