const now = new Date().toISOString();
return $input.all().map((item) => {
  const j = item.json || {};
  const workflowName = j.WorkflowName || j.workflowName || j.sourceWorkflowName || $workflow.name || 'unknown';
  const workflowId = j.WorkflowID || j.workflowId || j.sourceWorkflowId || $workflow.id || 'unknown';
  const logType = (j.logType || j.eventType || j.status || 'INFO').toString().toUpperCase();
  const correlationId = j.correlationId || crypto.randomUUID();
  const payload = redact({
    correlationId,
    event: logType,
    message: j.message || j.summary || null,
    businessKey: j.businessKey || j.recordId || j.customerId || null,
    durationMs: j.durationMs || null,
    status: j.status || null,
    data: j.logData || j.BusinessData || j.payload || j.body || j,
  });

  return {
    json: {
      logID: `AUD-${Date.now()}-${crypto.randomUUID().slice(0, 8)}`,
      logType,
      logDate: now,
      WorkflowName: String(workflowName),
      WorkflowID: String(workflowId),
      logData: safeStringify(payload),
    }
  };
});

// Configure retention here, or pass retentionDays into this workflow input.
// Default = 90 days.
const retentionDays = Number($json.retentionDays || 90);
const dryRun = String($json.dryRun || 'false').toLowerCase() === 'true';
const purgeBefore = new Date(Date.now() - retentionDays * 24 * 60 * 60 * 1000).toISOString();
return [{ json: { retentionDays, dryRun, purgeBeforeISO: purgeBefore } }];

return [{
  json: {
    logType: 'PURGE',
    WorkflowName: $workflow.name,
    WorkflowID: $workflow.id,
    message: `Purged Data Table rows older than ${$('Build Purge Config').item.json.retentionDays} days`,
    logData: {
      retentionDays: $('Build Purge Config').item.json.retentionDays,
      purgeBeforeISO: $('Build Purge Config').item.json.purgeBeforeISO,
      note: 'Check Data Table delete node execution output for row counts / dry-run results.'
    }
  }
}];
